(window.webpackJsonp=window.webpackJsonp||[]).push([[394],{1021:function(r,n){r.exports='\x3c!-- \r\ntitle: 03-H5基础\r\nsort: \r\n--\x3e \r\n# HTML5\r\n\r\n## First\r\n\r\n```html\r\n<!DOCTYPE html>\r\n<html>\r\n<head>\r\n<meta charset="utf-8">\r\n<title>文档标题</title>\r\n</head>\r\n \r\n<body>\r\n文档内容......\r\n</body>\r\n \r\n</html>\r\n```\r\n\r\n## Video\r\n\r\n```html\r\n<!DOCTYPE HTML>\r\n<html>\r\n<head>\r\n<meta charset="utf-8"> \r\n<title>Video</title> \r\n</head>\r\n<body>\r\n\r\n<video width="320" height="240" controls>\r\n  <source src="https://www.runoob.com/try/demo_source/movie.mp4" type="video/mp4">\r\n  <source src="https://www.runoob.com/try/demo_source/movie.ogg" type="video/ogg">\r\n  你的浏览器不支持 video 标签。\r\n</video>\r\n\r\n</body>\r\n</html>\r\n```\r\n\r\n## 浏览器支持\r\n\r\n```css\r\nheader, section, footer, aside, nav, main, article, figure {\r\n    display: block; \r\n}\r\n```\r\n\r\n## Creat New Element\r\n\r\n```html\r\n<!DOCTYPE html>\r\n<html>\r\n<head>\r\n<meta charset="utf-8"> \r\n<title>为 HTML 添加新元素</title>\r\n     \r\n\x3c!-- For IE --\x3e\r\n<script>\r\n    document.createElement("myHero")\r\n<\/script>\r\n\r\n<style>\r\nmyHero {\r\n    display: block;\r\n    background-color: #ddd;\r\n    padding: 50px;\r\n    font-size: 30px;\r\n}\r\n</style> \r\n</head>\r\n \r\n<body>\r\n \r\n<h1>我的第一个标题</h1>\r\n \r\n<p>我的第一个段落。</p>\r\n \r\n<myHero>我的第一个新元素</myHero>\r\n \r\n</body>\r\n</html>\r\n```\r\n\r\n'}}]);